<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/order/add"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "customerName": "b",
    "customerPhone": "0425593142",
    "deliveryWardName": "architecto",
    "deliveryWardCode": "architecto",
    "deliveryDistrictId": 16,
    "deliveryProvinceId": 16,
    "deliveryDistrictName": "architecto",
    "deliveryProvinceName": "architecto",
    "deliveryAddress": "architecto",
    "order_items": [
        {
            "productVariantId": 16,
            "quantity": 22
        }
    ],
    "paymentType": "COD",
    "point": 27,
    "note": "n",
    "voucherId": 16
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

